def validate_offer_statement(offer_statement: str) -> dict:
    """Validate Irresistible Offer Statement has all 6 components."""
    components = {
        "product": False,
        "specific_audience": False,
        "desired_outcome": False,
        "main_frustration": False,
        "mechanism": False,
        "timeframe": False
    }

    # Check for component indicators
    lower = offer_statement.lower()

    if "helps" in lower or "for" in lower:
        components["product"] = True
        components["specific_audience"] = True

    if "achieve" in lower or "get" in lower or "become" in lower:
        components["desired_outcome"] = True

    if "without" in lower or "no more" in lower:
        components["main_frustration"] = True

    if "by using" in lower or "through" in lower or "with" in lower:
        components["mechanism"] = True

    if any(t in lower for t in ["days", "weeks", "hours", "minutes", "month"]):
        components["timeframe"] = True

    score = sum(components.values())
    passed = score >= 5

    return {
        "passed": passed,
        "score": score,
        "max_score": 6,
        "components": components,
        "missing": [k for k, v in components.items() if not v]
    }


def validate_triangulated_proof(proof_sources: dict) -> dict:
    """Validate idea has proof from at least 2 of 3 sources."""
    sources = {
        "marketplace": bool(proof_sources.get("marketplace")),
        "ads": bool(proof_sources.get("ads")),
        "community": bool(proof_sources.get("community"))
    }

    source_count = sum(sources.values())
    passed = source_count >= 2

    return {
        "passed": passed,
        "source_count": source_count,
        "sources": sources,
        "missing": [k for k, v in sources.items() if not v],
        "recommendation": "Proceed" if passed else "Pivot angle or find more proof"
    }

def calculate_10x_value(price: float, deliverables: list) -> dict: """Calculate if deliverables provide 10x perceived value.""" target_value = price * 10
# Value weights per deliverable type value_weights = { "module": 50, "template": 100, "script": 75, "checklist": 50, "tool": 200, "coaching_session": 300, "community_access": 150, "ai_assistant": 250, "done_for_you": 500 }
total_value = 0 for d in deliverables: d_type = d.get("type", "module") total_value += value_weights.get(d_type, 50) * d.get("quantity", 1)
ratio = total_value / price if price > 0 else 0 passed = ratio >= 10
return { "passed": passed, "perceived_value": total_value, "price": price, "value_ratio": round(ratio, 1), "target_ratio": 10, "gap": max(0, target_value - total_value), "recommendation": "Add more value" if not passed else "Value justified" }


def validate_validation_thresholds(visitors: int, waitlist_signups: int, presales: int = 0) -> dict:
    """Check validation thresholds for product viability."""
    waitlist_rate = waitlist_signups / visitors if visitors > 0 else 0

    waitlist_passed = waitlist_rate >= 0.15 and visitors >= 500
    presell_passed = presales >= 10 and waitlist_signups >= 100

    overall_passed = waitlist_passed or presell_passed

    return {
        "passed": overall_passed,
        "waitlist_threshold": {
            "passed": waitlist_passed,
            "rate": round(waitlist_rate * 100, 1),
            "target_rate": 15,
            "visitors": visitors,
            "signups": waitlist_signups
        },
        "presell_threshold": {
            "passed": presell_passed,
            "presales": presales,
            "target": 10
        },
        "recommendation": "Proceed to build" if overall_passed else "Pivot before building"
    }


def validate_offer_ladder(tiers: list) -> dict:
    """Validate offer ladder has proper tier structure."""
    issues = []

    if len(tiers) < 2:
        issues.append("Need at least 2 tiers")

    # Check price progression
    prices = [t.get("price", 0) for t in tiers]
    if prices != sorted(prices):
        issues.append("Prices should increase with tier level")

    # Check support level progression
    support_levels = ["self_serve", "community", "group", "coaching", "vip"]
    for i, tier in enumerate(tiers):
        support = tier.get("support_level", "")
        if support not in support_levels:
            issues.append(f"Unknown support level: {support}")

    # Check differentiation is by support, not content
    content_based = any(
        "more videos" in str(t.get("differentiator", "")).lower() or
        "more modules" in str(t.get("differentiator", "")).lower()
        for t in tiers
    )
    if content_based:
        issues.append("Tier differentiation should be by SUPPORT level, not content volume")

    passed = len(issues) == 0

    return {
        "passed": passed,
        "tier_count": len(tiers),
        "issues": issues,
        "tiers": tiers
    }

def check_whole_solution_stack(components: dict) -> dict: """Check if product has all 4 Whole Solution Stack components.""" stack = { "physical": bool(components.get("physical")), "digital": bool(components.get("digital")), "community": bool(components.get("community")), "ai": bool(components.get("ai")) }
present = sum(stack.values()) passed = present >= 3 # At least 3 of 4
return { "passed": passed, "components_present": present, "components": stack, "missing": [k for k, v in stack.items() if not v], "note": "Physical optional for digital-first products" }

def validate_breakthrough_week1(onboarding_plan: dict) -> dict: """Validate product has measurable breakthrough in Week 1-2.""" days = onboarding_plan.get("days", [])
has_orientation = any("orientation" in str(d).lower() for d in days[:2]) has_quick_win = any("win" in str(d).lower() or "breakthrough" in str(d).lower() for d in days[:14]) has_do_actions = any("do" in str(d).lower() or "action" in str(d).lower() for d in days[:7]) has_celebration = any("celebrat" in str(d).lower() or "milestone" in str(d).lower() for d in days[:14])
score = sum([has_orientation, has_quick_win, has_do_actions, has_celebration]) passed = score >= 3
return { "passed": passed, "score": score, "max_score": 4, "checks": { "has_orientation": has_orientation, "has_quick_win": has_quick_win, "has_do_actions": has_do_actions, "has_celebration": has_celebration }, "recommendation": "Redesign Week 1-2 until measurable quick win exists" if not passed else "Breakthrough present" }
